{
  "title": "学校房间用途分类整理",
  "description": "根据学校用房分类口径文档，对提供的学校房间列表进行准确的用途分类，并输出为Excel表格格式",
  "requirements": "- 严格按照用户提供的分类口径文档进行房间分类\n- 保持原有房间名称和顺序不变\n- 准确填写每个房间的用途分类\n- 输出为Excel表格格式\n- 确保分类的准确性和一致性",
  "constraints": "- 必须使用用户提供的分类口径标准\n- 不能改变房间名称和顺序\n- 每个房间都必须有明确的分类\n- 分类结果需要逻辑一致",
  "references": "- {\n    \"id\": \"classification_doc\",\n    \"type\": \"file\", \n    \"name\": \"学校用房分类口径.docx\",\n    \"function\": \"提供学校房间用途分类的标准和口径\"\n  }",
  "expected_outcome": "一个完整的Excel表格，包含所有房间名称和对应的用途分类，分类准确且符合标准口径",
  "confidence": {
    "score": 0.75,
    "missing_info": [
      "需要获取分类口径文档的具体内容",
      "需要了解分类标准的详细定义"
    ]
  }
}

{
  "title": "银行账户数据规范化处理",
  "description": "对银行账户数据表进行规范化处理，包括日期格式统一、空值填充、小数位规范和去重，最终输出标准化的Excel文件",
  "requirements": [
    "将开户日期统一为YYYY-MM-DD格式",
    "账户余额和贷款金额列的空白值(nan)填充为0",
    "账户余额列数值保留2位小数",
    "删除所有列完全相同的重复数据行",
    "输出处理后的数据为Excel格式文件"
  ],
  "constraints": [
    "保持原始数据的完整性，只进行格式规范化",
    "确保数值计算的准确性",
    "保留所有有效的唯一数据记录"
  ],
  "references": [
    {
      "id": "user_data_table",
      "type": "file",
      "name": "银行账户数据表.md",
      "function": "包含用户姓名、手机号码、身份证号码、账户类型、开户日期、账户余额、贷款金额、贷款日期、贷款期限等银行客户信息的原始数据表格"
    }
  ],
  "expected_outcome": "生成一个规范化处理后的Excel文件，包含：统一格式的开户日期、填充0值的空白字段、保留2位小数的账户余额、去除重复后的唯一数据记录，便于用户下载使用",
  "confidence": {
    "score": 0.95,
    "missing_info": []
  }
}

{
  "title": "医院标识图片颜色修改任务",
  "description": "将自贡市第一人民医院绿色主色调的标识图片修改为红色主色调版本，用于颜色效果对比",
  "requirements": [
    "将原图片的绿色主色调改为正红色",
    "保持原有的文字内容和布局不变",
    "保持图片的整体设计风格和专业感",
    "确保修改后的图片清晰度不降低"
  ],
  "constraints": [
    "必须基于用户提供的原始图片进行修改",
    "不能改变医院名称和英文翻译",
    "保持标志的可识别性",
    "颜色修改要自然协调"
  ],
  "references": [
    {
      "id": "hospital_logo",
      "type": "file",
      "name": "自贡市第一人民医院标识图片",
      "function": "作为颜色修改的源文件，包含医院中英文名称和圆形徽标"
    }
  ],
  "expected_outcome": "生成一张以正红色为主色调的自贡市第一人民医院标识图片，保持原有设计元素和专业感，用于与原绿色版本进行视觉效果对比",
  "confidence": {
    "score": 0.95,
    "missing_info": []
  }
}

